// Define a structure for the priority queue element
// We prioritize minimum time (t), then maximum color (c).
// Since C++ std::priority_queue is a max-heap, we store (-t, -c) to simulate min-heap on t and max-heap on c.
// Wait, if we store (t, -c), the max-heap will prioritize min t (smallest t) and then max (-c) which means min c. This is wrong.
// We need (t, -c) where we want minimum t, and if t is equal, minimum -c (which means maximum c).
// Standard C++ priority_queue: stores element, compares using operator<.

// Let's use a custom comparison or store (t, c) and negate the comparison logic.
// PQ stores: {time, color, r, c}
// We want: min time, max color.

struct State {
    long long t; // time
    long long c; // color
    int r;       // row
    int col;     // column

    // Overload operator< for std::priority_queue (which is a max-heap)
    // We define 'less than' such that the element we want to pop first (minimum t, maximum c) 
    // is considered the 'greatest' in the max-heap context.
    bool operator>(const State& other) const {
        if (t != other.t) {
            return t > other.t; // Smaller time is 'greater' (higher priority)
        }
        return c < other.c; // Larger color is 'greater' (higher priority)
    }
};


