    for (const auto& source : sources) {
        long long r_i = source[0];
        long long c_i = source[1];
        long long color_i = source[2];
        int r = (int)r_i;
        int c = (int)c_i;

        // Handle potential duplicates, though problem statement guarantees unique locations
        if (D[r][c] == -1) {
            D[r][c] = 0;
            C_final[r][c] = color_i;
            pq.push({0, color_i, r, c});
        } else {
