             if (color_i > C_final[r][c]) {
                 C_final[r][c] = color_i;
                 // Re-pushing might be necessary if we assume the initial state could change, 
                 // but since T=0 is fixed, we only update color and rely on Dijkstra logic.
             }
        }
    }

    int dr[] = {-1, 1, 0, 0};
    int dc[] = {0, 0, -1, 1};

