            long long c_old = C_final[nr][nc];

            bool updated = false;

            if (t_old == -1) {
                // Case 1: Unreached cell (Infinity time)
                updated = true;
            } else if (t_new < t_old) {
                // Case 2: Strictly faster path
                updated = true;
            } else if (t_new == t_old) {
                // Case 3: Arriving at the same time. Check for max color.
                if (c_new > c_old) {
                    updated = true;
                }
            }

            if (updated) {
                // Update state
                D[nr][nc] = t_new;
                C_final[nr][nc] = c_new;

                // Push new state to PQ
                pq.push({t_new, c_new, nr, nc});
            }
        }
    }

    // Convert result back to vector<vector<long long>>
    vector<vector<long long>> result(R, vector<long long>(C_grid));
    for (int i = 0; i < R; ++i) {
        for (int j = 0; j < C_grid; ++j) {
            result[i][j] = C_final[i][j];
        }
    }

    return result;
}

