using namespace std;

typedef long long ll;

// Define a structure for the Priority Queue elements
// {distance, -color, row, col}
// We use -color to make the standard min-heap prioritize larger colors when distances are equal.
struct State {
    ll dist;
    ll neg_color;
    ll r;
    ll c;

    // Custom comparator for the min-heap
    bool operator>(const State& other) const {
        if (dist != other.dist) {
            return dist > other.dist; // Primary key: smaller distance first
        }
        return neg_color > other.neg_color; // Secondary key: smaller negative_color (i.e., larger color) first
    }
};

vector<vector<ll>> solve(ll n, ll m, vector<vector<ll>>& sources) {
    // Initialize the result grid R (stores the final color)
    vector<vector<ll>> R(n, vector<ll>(m, 0));

    // Initialize the distance grid D (stores minimum arrival time)
    // We use a value larger than the maximum possible distance (N*M) for infinity
    const ll INF = n * m + 1;
    vector<vector<ll>> D(n, vector<ll>(m, INF));

    // Min-priority queue
    priority_queue<State, vector<State>, greater<State>> pq;

    // 1. Seed the queue with initial sources
    for (const auto& source : sources) {
        ll r = source[0];
        ll c = source[1];
        ll color = source[2];

        if (D[r][c] > 0) { // Should always be true if sources are unique, but good practice
            D[r][c] = 0;
            R[r][c] = color;
            pq.push({0, -color, r, c});
        }
    }

    int dr[] = {-1, 1, 0, 0};
    int dc[] = {0, 0, -1, 1};

    // 2. Dijkstra-like processing
    while (!pq.empty()) {
        State current = pq.top();
        pq.pop();

        ll d = current.dist;
        ll c = -current.neg_color;
        ll r = current.r;
        ll c_coord = current.c; // Renamed c to c_coord to avoid conflict with color c

        // Stale check: If we found a faster way previously, or reached this cell at the same time but with a better color, skip.
        // Since the PQ prioritizes the best state, we mainly check against the recorded distance.
        if (d > D[r][c_coord]) {
            continue;
        }
        // If distance is the same, but the recorded color R[r][c_coord] is strictly better than c, skip.
        // This handles cases where a higher color arrived earlier in the PQ processing loop.
        if (d == D[r][c_coord] && c < R[r][c_coord]) {
            continue;
        }

        // Propagate to neighbors
        for (int i = 0; i < 4; ++i) {
            ll nr = r + dr[i];
            ll nc = c_coord + dc[i];

            // Boundary check
            if (nr < 0 || nr >= n || nc < 0 || nc >= m) {
                continue;
            }

            ll new_dist = d + 1;

            // Case 1: Strictly shorter path found
            if (new_dist < D[nr][nc]) {
                D[nr][nc] = new_dist;
                R[nr][nc] = c;
                pq.push({new_dist, -c, nr, nc});
            } 
            // Case 2: Equal path length found (Time tie)
            else if (new_dist == D[nr][nc]) {
                // Apply the rule: take the maximum color
                if (c > R[nr][nc]) {
                    R[nr][nc] = c;
                    // Crucially, re-push the state to propagate this superior color immediately
                    pq.push({new_dist, -c, nr, nc});
